import React, { useEffect, useState } from 'react';
import { adminService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/admin/admin-dashboard.css';
import '../../styles/admin-layout.css';
import { pushToast } from '../../utils/toastBridge'

export const AdminDashboard = () => {
  const [users, setUsers] = useState([]);
  const [recentLogins, setRecentLogins] = useState([]);
  const [loginTrend, setLoginTrend] = useState([]);
  const [loading, setLoading] = useState(true);
  const error = null;
  useEffect(() => {
    fetchDashboardData();
  }, []);

  const getMonthKey = (date) => {
    const y = date.getFullYear();
    const m = String(date.getMonth() + 1).padStart(2, '0');
    return `${y}-${m}`;
  };

  const buildLoginTrend = (logs) => {
    const now = new Date();
    const months = [];

    for (let i = 5; i >= 0; i -= 1) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      months.push({
        key: getMonthKey(d),
        label: `Th${d.getMonth() + 1}`,
        count: 0,
      });
    }

    const monthMap = months.reduce((acc, item) => {
      acc[item.key] = item;
      return acc;
    }, {});

    logs.forEach((log) => {
      const parsed = new Date(log.logged_at || log.created_at || Date.now());
      const key = getMonthKey(parsed);
      if (monthMap[key]) {
        monthMap[key].count += 1;
      }
    });

    return months;
  };

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      const [usersResponse, loginResponse] = await Promise.all([
        adminService.getAllUsers(),
        adminService.getActivityLogs({ action: 'LOGIN', limit: 120 }),
      ]);

      const userData = usersResponse?.data?.data || [];
      const loginData = loginResponse?.data?.data || [];

      loginData.sort((a, b) => new Date(b.logged_at) - new Date(a.logged_at));

      setUsers(userData);
      setRecentLogins(loginData.slice(0, 6));
      setLoginTrend(buildLoginTrend(loginData));
      pushToast({ title: 'Thất bại', message: '', type: 'error' });
    } catch (err) {
      pushToast({ title: 'Thất bại', message: 'Lá»—i táº£i dá»¯ liá»‡u dashboard admin', type: 'error' });
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const activeCount = users.filter((u) => u.status === true || u.status === 'true' || u.status === 1).length;
  const lockedCount = users.length - activeCount;

  const now = new Date();
  const newUsersThisMonth = users.filter((u) => {
    if (!u.created_at) return false;
    const createdAt = new Date(u.created_at);
    return createdAt.getMonth() === now.getMonth() && createdAt.getFullYear() === now.getFullYear();
  }).length;

  const ownerCount = users.filter((u) => String(u.role || '').toUpperCase() === 'OWNER').length;

  const maxTrend = Math.max(...loginTrend.map((item) => item.count), 1);
  const svgWidth = 540;
  const svgHeight = 220;
  const padding = 28;
  const chartWidth = svgWidth - padding * 2;
  const chartHeight = svgHeight - padding * 2;

  const linePoints = loginTrend.map((item, index) => {
    const x = padding + (chartWidth / Math.max(loginTrend.length - 1, 1)) * index;
    const y = padding + chartHeight - (item.count / maxTrend) * chartHeight;
    return { ...item, x, y };
  });

  const linePath = linePoints
    .map((point, index) => `${index === 0 ? 'M' : 'L'} ${point.x} ${point.y}`)
    .join(' ');

  const activePercent = users.length ? Math.round((activeCount / users.length) * 100) : 0;
  const lockedPercent = Math.max(0, 100 - activePercent);

  const alerts = [
    {
      level: lockedCount > 0 ? 'warning' : 'success',
      message: lockedCount > 0 ? `CÃ³ ${lockedCount} tÃ i khoáº£n Ä‘ang bá»‹ khÃ³a` : 'KhÃ´ng cÃ³ tÃ i khoáº£n bá»‹ khÃ³a',
    },
    {
      level: ownerCount === 0 ? 'danger' : 'info',
      message: ownerCount === 0 ? 'ChÆ°a cÃ³ tÃ i khoáº£n OWNER nÃ o trong há»‡ thá»‘ng' : `Äang cÃ³ ${ownerCount} tÃ i khoáº£n OWNER`,
    },
    {
      level: recentLogins.length === 0 ? 'warning' : 'info',
      message: recentLogins.length === 0 ? 'KhÃ´ng cÃ³ hoáº¡t Ä‘á»™ng Ä‘Äƒng nháº­p gáº§n Ä‘Ã¢y' : `ÄÃ£ ghi nháº­n ${recentLogins.length} Ä‘Äƒng nháº­p gáº§n nháº¥t`,
    },
  ];

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center admin-dashboard__loading-container">
          <div className="spinner"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard admin-page admin-analytics">
      {error && <div className="alert alert-error">{error}</div>}

      <section className="admin-hero-grid">
        <article className="admin-kpi-card">
          <p className="admin-kpi-card__label">Tá»•ng ngÆ°á»i dÃ¹ng</p>
          <h3 className="admin-kpi-card__value">{users.length.toLocaleString('vi-VN')}</h3>
          <p className="admin-kpi-card__sub">ToÃ n bá»™ tÃ i khoáº£n trong há»‡ thá»‘ng</p>
        </article>

        <article className="admin-kpi-card">
          <p className="admin-kpi-card__label">NgÆ°á»i dÃ¹ng hoáº¡t Ä‘á»™ng</p>
          <div className="admin-kpi-card__row">
            <h3 className="admin-kpi-card__value">{activeCount.toLocaleString('vi-VN')}</h3>
            <span className="admin-pill admin-pill--success">Hoáº¡t Ä‘á»™ng</span>
          </div>
          <p className="admin-kpi-card__sub">{activePercent}% tá»•ng sá»‘ tÃ i khoáº£n</p>
        </article>

        <article className="admin-kpi-card">
          <p className="admin-kpi-card__label">TÃ i khoáº£n bá»‹ khÃ³a</p>
          <div className="admin-kpi-card__row">
            <h3 className="admin-kpi-card__value">{lockedCount.toLocaleString('vi-VN')}</h3>
            <span className="admin-pill admin-pill--warning">Cáº£nh bÃ¡o</span>
          </div>
          <p className="admin-kpi-card__sub">Cáº§n rÃ  soÃ¡t nguyÃªn nhÃ¢n khÃ³a</p>
        </article>

        <article className="admin-kpi-card">
          <p className="admin-kpi-card__label">NgÆ°á»i dÃ¹ng má»›i thÃ¡ng nÃ y</p>
          <div className="admin-kpi-card__row">
            <h3 className="admin-kpi-card__value">{newUsersThisMonth.toLocaleString('vi-VN')}</h3>
            <span className="admin-pill admin-pill--info">TÄƒng</span>
          </div>
          <p className="admin-kpi-card__sub">TÄƒng trÆ°á»Ÿng theo thÃ¡ng hiá»‡n táº¡i</p>
        </article>
      </section>

      <section className="admin-chart-grid">
        <article className="card admin-chart-card">
          <div className="admin-card-header">
            <h3>Thá»‘ng kÃª Ä‘Äƒng nháº­p</h3>
          </div>
          <div className="admin-line-chart">
            {loginTrend.length > 0 ? (
              <svg viewBox={`0 0 ${svgWidth} ${svgHeight}`} aria-label="Biá»ƒu Ä‘á»“ Ä‘Äƒng nháº­p">
                {[0, 1, 2, 3].map((line) => {
                  const y = padding + (chartHeight / 3) * line;
                  return (
                    <line
                      key={`grid-${line}`}
                      x1={padding}
                      y1={y}
                      x2={svgWidth - padding}
                      y2={y}
                      className="admin-line-chart__grid"
                    />
                  );
                })}

                <path d={linePath} className="admin-line-chart__path" />

                {linePoints.map((point) => (
                  <g key={point.key}>
                    <circle cx={point.x} cy={point.y} r="4" className="admin-line-chart__dot" />
                    <text x={point.x} y={svgHeight - 6} textAnchor="middle" className="admin-line-chart__label">
                      {point.label}
                    </text>
                  </g>
                ))}
              </svg>
            ) : (
              <p>ChÆ°a cÃ³ dá»¯ liá»‡u Ä‘Äƒng nháº­p Ä‘á»ƒ hiá»ƒn thá»‹ biá»ƒu Ä‘á»“.</p>
            )}
          </div>
        </article>

        <article className="card admin-chart-card">
          <div className="admin-card-header">
            <h3>PhÃ¢n tÃ­ch hoáº¡t Ä‘á»™ng ngÆ°á»i dÃ¹ng</h3>
          </div>

          <div className="admin-donut-wrap">
            <div
              className="admin-donut"
              style={{ background: `conic-gradient(#2563eb 0 ${activePercent}%, #93c5fd ${activePercent}% 100%)` }}
            >
              <div className="admin-donut__center">
                <span>{activePercent}%</span>
              </div>
            </div>

            <div className="admin-donut-legend">
              <div><span className="dot dot--active" /> Hoáº¡t Ä‘á»™ng: {activeCount}</div>
              <div><span className="dot dot--idle" /> Bá»‹ khÃ³a: {lockedCount}</div>
              <div><span className="dot dot--light" /> KhÃ´ng hoáº¡t Ä‘á»™ng: {lockedPercent}%</div>
            </div>
          </div>
        </article>
      </section>

      <section className="admin-bottom-grid">
        <article className="card admin-table-card">
          <div className="admin-card-header">
            <h3>Nháº­t kÃ½ Ä‘Äƒng nháº­p gáº§n Ä‘Ã¢y</h3>
            <a className="btn btn-secondary btn-sm" href="/admin/user-login-history">Xem Ä‘áº§y Ä‘á»§</a>
          </div>

          <div className="admin-login-table-wrap">
            <table className="admin-login-table">
              <thead>
                <tr>
                  <th>TÃªn ngÆ°á»i dÃ¹ng</th>
                  <th>Username</th>
                  <th>Thá»i gian</th>
                  <th>Tráº¡ng thÃ¡i</th>
                </tr>
              </thead>
              <tbody>
                {recentLogins.length === 0 ? (
                  <tr>
                    <td colSpan="4" className="admin-table-empty">ChÆ°a cÃ³ hoáº¡t Ä‘á»™ng Ä‘Äƒng nháº­p gáº§n Ä‘Ã¢y.</td>
                  </tr>
                ) : (
                  recentLogins.map((log) => (
                    <tr key={`login-${log.audit_id}`}>
                      <td>{log.actor_full_name || `NgÆ°á»i dÃ¹ng #${log.user_id}`}</td>
                      <td>{log.actor_username || '-'}</td>
                      <td>
                        {new Date(log.logged_at).toLocaleString('vi-VN', {
                          year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit',
                        })}
                      </td>
                      <td><span className="admin-status admin-status--success">ThÃ nh cÃ´ng</span></td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </article>

        <article className="card admin-alerts-card">
          <div className="admin-card-header">
            <h3>Cáº£nh bÃ¡o há»‡ thá»‘ng</h3>
          </div>

          <ul className="admin-alert-list">
            {alerts.map((alertItem, index) => (
              <li key={`alert-${index}`} className={`admin-alert-item admin-alert-item--${alertItem.level}`}>
                <span className="admin-alert-icon">âš </span>
                <span>{alertItem.message}</span>
              </li>
            ))}
          </ul>

          <div className="admin-alert-actions">
            <a className="btn btn-primary" href="/admin/users">Quáº£n lÃ½ ngÆ°á»i dÃ¹ng</a>
            <a className="btn btn-secondary" href="/admin/activity-logs">Xem nháº­t kÃ½</a>
          </div>
        </article>
      </section>
    </div>
  );
};

export default AdminDashboard;
